import{_ as e}from"./chunks/panel-l4-relay-form.DSQdNitK.js";import{_ as a,o as d,c as r,a2 as l}from"./chunks/framework.CuEaBji2.js";const s="/nginx-reverse-emby/screenshots/panel-relay-form.png",o="/nginx-reverse-emby/screenshots/panel-relay-listener.png",g=JSON.parse('{"title":"Relay 隧道","description":"","frontmatter":{},"headers":[],"relativePath":"guides/relay.md","filePath":"guides/relay.md","lastUpdated":1782021666000}'),n={name:"guides/relay.md"};function i(h,t,p,c,y,m){return d(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="relay-隧道" tabindex="-1">Relay 隧道 <a class="header-anchor" href="#relay-隧道" aria-label="Permalink to &quot;Relay 隧道&quot;">​</a></h1><p>Relay 在 Agent 之间建立加密通道。流量经过中继节点再到后端，适合入口节点无法直连后端、需要利用中继节点线路优势的场景。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>控制面已部署并正常运行</li><li>至少有两个 Agent 节点（一个做入口，一个做中继）</li><li>中继节点的监听端口在防火墙中放行</li></ul><h2 id="创建-relay-监听器" tabindex="-1">创建 Relay 监听器 <a class="header-anchor" href="#创建-relay-监听器" aria-label="Permalink to &quot;创建 Relay 监听器&quot;">​</a></h2><p>进入 <strong>基础设施 → Relay 监听器</strong>，选中继节点，点击 <strong>新建监听器</strong>。</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td><code>relay-fast-vps</code></td><td>给中继起个名字</td></tr><tr><td>监听证书来源</td><td>自动签发（Relay CA）</td><td>默认即可，系统自动维护证书</td></tr><tr><td>绑定地址</td><td><code>0.0.0.0</code></td><td>监听所有网卡</td></tr><tr><td>监听端口</td><td><code>7443</code></td><td>中继节点实际监听的端口</td></tr><tr><td>公网入口</td><td><code>relay.example.com:7443</code></td><td>其他节点连接中继时用的地址</td></tr><tr><td>传输方式</td><td><code>TLS/TCP</code></td><td>新手用默认值，熟悉后可试 QUIC 或 WireGuard</td></tr></tbody></table><p><img src="'+s+'" alt="创建 Relay 监听器"></p><p>保存后在列表中确认监听器已启用。</p><p><img src="'+o+'" alt="Relay 监听器列表"></p><h2 id="在规则中使用-relay" tabindex="-1">在规则中使用 Relay <a class="header-anchor" href="#在规则中使用-relay" aria-label="Permalink to &quot;在规则中使用 Relay&quot;">​</a></h2><p>创建 HTTP 或 L4 规则时，在 <strong>Relay 配置</strong> 标签页点击 <strong>添加 Relay 层</strong>，选择刚创建的 Relay 监听器。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 → 入口 Agent → Relay 隧道 → 出站 Agent → 后端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>每层可以放多个 Relay 监听器作为并行候选，多层表示按顺序逐跳转发。新手先配一层一个节点，跑通后再扩展。</p><p><img src="'+e+'" alt="L4 Relay 配置"></p><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h2><p>保存规则后回到列表，规则卡片带 <code>Relay</code> 标记说明已关联隧道。测试入口端口或域名确认连通。</p><h2 id="relay-vs-直接转发" tabindex="-1">Relay vs 直接转发 <a class="header-anchor" href="#relay-vs-直接转发" aria-label="Permalink to &quot;Relay vs 直接转发&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>用 Relay</th><th>直接转发</th></tr></thead><tbody><tr><td>入口节点能直连后端</td><td>不需要</td><td>✓</td></tr><tr><td>入口节点无法直连后端</td><td>✓</td><td>不通</td></tr><tr><td>想利用中继节点线路</td><td>✓</td><td>不需要</td></tr><tr><td>需要多跳（A→B→C→后端）</td><td>✓</td><td>不支持</td></tr></tbody></table><p>深入了解 Relay 的协议细节，见 <a href="./../reference/relay-internals">Relay 协议内幕</a>。</p>',20)])])}const _=a(n,[["render",i]]);export{g as __pageData,_ as default};
